@Controller
class AppController {
    @GetMapping("/")
    @ResponseBody
    public String home(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) return "No session";
        Object principal = session.getAttribute(SamlSessionKeys.PRINCIPAL);
        Object attrs = session.getAttribute(SamlSessionKeys.ATTRIBUTES);
        return "Authenticated principal=" + principal + "\nattributes=" + attrs;
    }

    @GetMapping("/protected")
    @ResponseBody
    public String protectedEndpoint(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        return "OK principal=" + session.getAttribute(SamlSessionKeys.PRINCIPAL);
    }

    @GetMapping("/logout")
    @ResponseBody
    public String logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        return "Logged out";
    }
}

@RestController
@RequestMapping("/saml")
class SamlAcsController {

    private final SamlResponseProcessor processor = new SamlResponseProcessor();

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public void acs(@RequestParam MultiValueMap<String, String> form,
                    HttpServletRequest request,
                    HttpServletResponse response) throws Exception {

        String samlResponse = first(form, "SAMLResponse");
        if (samlResponse == null || samlResponse.isBlank()) {
            response.sendError(400, "Missing SAMLResponse");
            return;
        }

        SamlAuthenticationResult result = processor.processBase64EncodedSamlResponse(samlResponse);

        HttpSession session = request.getSession(true);
        session.setAttribute(SamlSessionKeys.AUTHENTICATED, Boolean.TRUE);
        session.setAttribute(SamlSessionKeys.PRINCIPAL, result.getNameId());
        session.setAttribute(SamlSessionKeys.ISSUER, result.getIssuer());
        session.setAttribute(SamlSessionKeys.SESSION_INDEX, result.getSessionIndex());
        session.setAttribute(SamlSessionKeys.NOT_ON_OR_AFTER, result.getNotOnOrAfterEpochSeconds());
        session.setAttribute(SamlSessionKeys.ATTRIBUTES, result.getAttributes());
        session.setAttribute(SamlSessionKeys.RAW_ASSERTION_XML, result.getRawAssertionXml());

        String relayState = first(form, "RelayState");
        if (relayState != null && !relayState.isBlank() && isSafeRelativeRedirect(relayState)) {
            response.sendRedirect(relayState);
        } else {
            response.sendRedirect("/");
        }
    }

    private static String first(MultiValueMap<String, String> map, String key) {
        List<String> v = map.get(key);
        return (v == null || v.isEmpty()) ? null : v.get(0);
    }

    private static boolean isSafeRelativeRedirect(String relayState) {
        if (relayState.startsWith("http://") || relayState.startsWith("https://")) return false;
        if (relayState.startsWith("//")) return false;
        if (!relayState.startsWith("/")) return false;
        return !relayState.contains("\r") && !relayState.contains("\n");
    }
}

