class RequireSamlSessionFilter extends OncePerRequestFilter {

    private static final Set<String> ALLOW = Set.of(
            "/", "/saml/acs", "/error", "/logout"
    );

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, java.io.IOException {

        String path = request.getRequestURI();
        if (path == null) path = "/";
        if (isAllowed(path)) {
            filterChain.doFilter(request, response);
            return;
        }

        HttpSession session = request.getSession(false);
        boolean authed = session != null && Boolean.TRUE.equals(session.getAttribute(SamlSessionKeys.AUTHENTICATED));

        if (!authed) {
            response.sendError(401, "Unauthenticated");
            return;
        }

        Long noa = asLong(session.getAttribute(SamlSessionKeys.NOT_ON_OR_AFTER));
        if (noa != null && Instant.now().getEpochSecond() >= noa) {
            session.invalidate();
            response.sendError(401, "Session expired");
            return;
        }

        filterChain.doFilter(request, response);
    }

    private static boolean isAllowed(String path) {
        if (ALLOW.contains(path)) return true;
        if (path.startsWith("/static/") || path.startsWith("/css/") || path.startsWith("/js/") || path.startsWith("/webjars/")) return true;
        return false;
    }

    private static Long asLong(Object v) {
        if (v == null) return null;
        if (v instanceof Long l) return l;
        if (v instanceof Integer i) return i.longValue();
        if (v instanceof String s) {
            try { return Long.parseLong(s); } catch (Exception ignored) {}
        }
        return null;
    }
}

